package travelcare_agent.evaluation;
import com.fasterxml.jackson.databind.ObjectMapper; import org.junit.jupiter.api.Test; import travelcare_agent.dryrun.*; import travelcare_agent.evaluation.entity.*; import travelcare_agent.evaluation.repository.*; import travelcare_agent.trace.TraceQueryService; import travelcare_agent.trace.entity.TraceRun; import travelcare_agent.trace.repository.TraceRunRepository; import java.time.*; import java.util.*; import static org.assertj.core.api.Assertions.assertThat; import static org.mockito.Mockito.*;
class EvaluationRunnerServiceTest {
 @Test void skippedCaseProducesPartialAndReportFailureIsRecorded()throws Exception{EvaluationDataset ds=new EvaluationDataset();ds.setId(1L);ds.setVersion(1);ds.setDatasetKey("refund");ds.setStatus("ACTIVE");EvaluationCase c=new EvaluationCase();c.setId(2L);c.setDatasetId(1L);c.setCaseKey("legacy");c.setName("Legacy");c.setSourceTraceId(3L);c.setExpectationJson("{}");EvaluationDatasetRepository datasets=mock(EvaluationDatasetRepository.class);when(datasets.findById(1L)).thenReturn(Optional.of(ds));EvaluationCaseRepository cases=mock(EvaluationCaseRepository.class);when(cases.findEnabledCasesByDatasetId(1L)).thenReturn(List.of(c));RunRepo runs=new RunRepo();ResultRepo results=new ResultRepo();TraceRun source=new TraceRun();source.setId(3L);source.setTraceId("legacy");TraceRunRepository traces=mock(TraceRunRepository.class);when(traces.findById(3L)).thenReturn(Optional.of(source));DryRunReadinessChecker readiness=mock(DryRunReadinessChecker.class);when(readiness.check("legacy","mock")).thenReturn(DryRunReadinessResult.rejected(List.of("POLICY_INPUT.evaluatedAt")));EvaluationRunReportWriter report=mock(EvaluationRunReportWriter.class);when(report.write(any(),any(),anyList(),anyList(),anyMap(),any())).thenThrow(new java.io.IOException("disk full"));EvaluationSideEffectGuard guard=mock(EvaluationSideEffectGuard.class);when(guard.snapshot()).thenReturn(Map.of());EvaluationRunnerService service=new EvaluationRunnerService(datasets,cases,runs,results,traces,readiness,mock(DiagnosticDryRunService.class),mock(TraceQueryService.class),mock(TraceDiffService.class),List.of(),new EvaluationPromptStubRegistry(),guard,report,new ObjectMapper(),Clock.fixed(Instant.parse("2026-06-15T00:00:00Z"),ZoneOffset.UTC));EvaluationRun run=service.start(1L,null,null);assertThat(runs.statuses).containsSequence("PENDING","RUNNING");assertThat(run.getStatus()).isEqualTo("PARTIAL");assertThat(run.getSkippedCount()).isEqualTo(1);assertThat(run.getSummaryJson()).contains("reportError","disk full");assertThat(results.values).singleElement().satisfies(r->{assertThat(r.getStatus()).isEqualTo("SKIPPED");assertThat(r.getDryRunTraceId()).isNull();});}
 @Test void comparisonFailurePreservesOriginalResultsAndRecordsComparisonError()throws Exception{EvaluationDataset ds=new EvaluationDataset();ds.setId(1L);ds.setVersion(1);ds.setDatasetKey("refund");ds.setStatus("ACTIVE");ds.setCurrentBaselineRunId(99L);EvaluationCase c=new EvaluationCase();c.setId(2L);c.setDatasetId(1L);c.setCaseKey("legacy");c.setName("Legacy");c.setSourceTraceId(3L);c.setExpectationJson("{}");EvaluationDatasetRepository datasets=mock(EvaluationDatasetRepository.class);when(datasets.findById(1L)).thenReturn(Optional.of(ds));EvaluationCaseRepository cases=mock(EvaluationCaseRepository.class);when(cases.findEnabledCasesByDatasetId(1L)).thenReturn(List.of(c));RunRepo runs=new RunRepo();ResultRepo results=new ResultRepo();TraceRun source=new TraceRun();source.setId(3L);source.setTraceId("legacy");TraceRunRepository traces=mock(TraceRunRepository.class);when(traces.findById(3L)).thenReturn(Optional.of(source));DryRunReadinessChecker readiness=mock(DryRunReadinessChecker.class);when(readiness.check("legacy","mock")).thenReturn(DryRunReadinessResult.rejected(List.of("POLICY_INPUT.evaluatedAt")));BaselineComparisonService comparisons=mock(BaselineComparisonService.class);when(comparisons.compare(anyLong(),eq(99L))).thenThrow(new IllegalStateException("comparison unavailable"));EvaluationRunReportWriter report=mock(EvaluationRunReportWriter.class);when(report.write(any(),any(),anyList(),anyList(),anyMap(),any())).thenReturn(java.nio.file.Path.of("target/report.md"));EvaluationSideEffectGuard guard=mock(EvaluationSideEffectGuard.class);when(guard.snapshot()).thenReturn(Map.of());EvaluationRunnerService service=new EvaluationRunnerService(datasets,cases,runs,results,traces,readiness,mock(DiagnosticDryRunService.class),mock(TraceQueryService.class),mock(TraceDiffService.class),List.of(),new EvaluationPromptStubRegistry(),guard,report,comparisons,new ObjectMapper(),Clock.fixed(Instant.parse("2026-06-15T00:00:00Z"),ZoneOffset.UTC));EvaluationRun run=service.start(1L,"mock","stage8-default",true);assertThat(run.getRegressionStatus()).isEqualTo("PARTIAL");assertThat(run.getBaselineRunId()).isEqualTo(99L);assertThat(run.getSummaryJson()).contains("comparisonError","comparison unavailable");assertThat(results.values).singleElement().extracting(EvaluationCaseResult::getStatus).isEqualTo("SKIPPED");}
 private static class RunRepo implements EvaluationRunRepository{EvaluationRun value;long id;List<String> statuses=new ArrayList<>();public EvaluationRun save(EvaluationRun v){if(v.getId()==null)v.setId(++id);value=v;statuses.add(v.getStatus());return v;}public Optional<EvaluationRun> findById(Long id){return Optional.ofNullable(value);}}
 private static class ResultRepo implements EvaluationCaseResultRepository{List<EvaluationCaseResult> values=new ArrayList<>();public EvaluationCaseResult save(EvaluationCaseResult v){if(!values.contains(v))values.add(v);return v;}public List<EvaluationCaseResult> findResultsByRunId(Long id){return values;}public long countByRunIdAndStatus(Long id,String s){return values.stream().filter(v->s.equals(v.getStatus())).count();}}
}
